#include <omp.h>
#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <limits.h>
#include <sys/time.h>
#include <math.h>
#include <stdbool.h>
#include <stdint.h>

#include "../common.h"
#include "../util/timer/timer.h"
#ifdef TIMING
#include "../../util/timing.h"
#endif

#include "./kernel_gpu_opencl_wrapper.h"

void 
kernel_cpu(	int cores_arg,
			record *records,
			knode *knodes,
			long knodes_elem,

			int order,
			long maxheight,
			int count,

			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{

#ifdef TIMING
	struct timeval tv;
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_h2d_start, tv_h2d_end;
	struct timeval tv_d2h_start, tv_d2h_end;
	struct timeval tv_kernel_start, tv_kernel_end;
	struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time= 0,
		  d2h_time = 0, close_time = 0, total_time = 0;
#endif

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
	gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
	gettimeofday(&tv_mem_alloc_end, NULL);
	tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
	mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	int local_work_size = order < 1024 ? order : 1024;
	int num_threads = (cores_arg > 0) ? cores_arg : local_work_size;
	if (num_threads > local_work_size) num_threads = local_work_size;

	printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", count, num_threads);

#ifdef  TIMING
	gettimeofday(&tv_kernel_start, NULL);
#endif

#pragma omp parallel num_threads(num_threads)
{
	int thid = omp_get_thread_num();

#pragma omp for
	for(int bid = 0; bid < count; bid++) {

		long current_knode = currKnode[bid];
		long current_offset = offset[bid];

		int i;
		for(i = 0; i < maxheight; i++){

			if((knodes[current_knode].keys[thid] <= keys[bid]) && (knodes[current_knode].keys[thid+1] > keys[bid])){

				if(knodes[current_offset].indices[thid] < knodes_elem){
					current_offset = knodes[current_offset].indices[thid];
				}
			}

			if(thid==0){
				currKnode[bid] = current_offset;
			}
		}

		if(knodes[currKnode[bid]].keys[thid] == keys[bid]){
			ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
		}
	}
}

#ifdef  TIMING
	gettimeofday(&tv_kernel_end, NULL);
	tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
	kernel_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif

}

void 
kernel_gpu_opencl_wrapper(	record *records,
							long records_mem,
							knode *knodes,
							long knodes_elem,
							long knodes_mem,

							int order,
							long maxheight,
							int count,

							long *currKnode,
							long *offset,
							int *keys,
							record *ans)
{
	kernel_cpu(0, records, knodes, knodes_elem, order, maxheight, count, currKnode, offset, keys, ans);
}

